function A({children,delay=0,anim="fadeUp",dur=450,style={}}){if(bookV5||bookV6){const k=anim+'_'+bookSlideAnim;anim=V5_REMAP[k]||anim;}else if(!bookV4)anim=FALLBACK_ANIM[anim]||anim;if(bookV2){const a=BOOK_ANIM_MAP[anim]||anim;const d=Math.round(dur*1.8);const dl=Math.round(delay*2.2)+80;return <div style={{animation:`${a} ${d}ms ${BOOK_EO} ${dl}ms both`,...style}}>{children}</div>}if(bookMode){const d=Math.round(dur*1.6);const dl=Math.round(delay*1.4);return <div style={{animation:`bse${bookSlideAnim} ${d}ms ${BOOK_EO} ${dl}ms both`,...style}}>{children}</div>}return <div style={{animation:`${anim} ${dur}ms ${EO} ${delay}ms both`,...style}}>{children}</div>}

function SF({t,d=200}){if(!bookMode)return t;
const ORD_U='ABCDEFGHIJKLMNOPQRSTUVWXYZ',ORD_L='abcdefghijklmnopqrstuvwxyz',ORD_N='0123456789',TK=34,FP=5,RT=1,SG=1.4;
const ch=t.split('');const[fr,setFr]=useState(0);const dr=useRef(null);
useEffect(()=>{let wp=0;const data=ch.map((g,i)=>{if(g===' '){wp=0;return{g,seq:[' '],fi:0,tp:0,ph:'done',st:0,pv:'',cr:' '}}wp++;const isUp=g===g.toUpperCase()&&g!==g.toLowerCase();const al=isUp?ORD_U:ORD_L;const gi=al.indexOf(g);let seq;if(gi<0){const ni=ORD_N.indexOf(g);if(ni<0)seq=[g];else{const n=1+Math.floor(Math.random()*2);seq=[];for(let j=n;j>=1;j--)seq.push(ORD_N[(ni-j+ORD_N.length)%ORD_N.length]);seq.push(g)}}else{const n=2+Math.floor(Math.random()*2);seq=[];for(let j=n;j>=1;j--)seq.push(al[(gi-j+al.length)%al.length]);seq.push(g)}return{g,seq,fi:0,tp:0,ph:'wait',st:Math.round(d/TK+i*SG),pv:'',cr:''}});dr.current=data;let tick=0;const iv=setInterval(()=>{tick++;let dn=true;for(const c of data){if(c.ph==='done')continue;dn=false;if(c.ph==='wait'){if(tick>=c.st){c.ph='flip';c.tp=0;c.pv='';c.cr=c.seq[0];c.fi=0}continue}c.tp++;if(c.ph==='flip'&&c.tp>=FP){c.ph='rest';c.tp=0}else if(c.ph==='rest'&&c.tp>=RT){if(c.fi>=c.seq.length-1)c.ph='done';else{c.fi++;c.pv=c.cr;c.cr=c.seq[c.fi];c.ph='flip';c.tp=0}}}setFr(tick);if(dn)clearInterval(iv)},TK);return()=>clearInterval(iv)},[t,d]);
const data=dr.current;if(!data)return t;const words=t.split(' ');let ci=0;const FD_=FP*TK;
return <span style={{display:'inline-flex',flexWrap:'wrap',gap:'18px 2.5px',lineHeight:1,justifyContent:'center'}}>{words.map((w,wi)=>{const start=ci;ci+=w.length+1;return <span key={wi} style={{display:'inline-flex',gap:2.5,whiteSpace:'nowrap'}}>{data.slice(start,start+w.length).map((c,li)=>{const idx=start+li;const sp=c.g===' ';const fl=c.ph==='flip';const dn=c.ph==='done';return <span key={idx} style={{display:'inline-flex',alignItems:'center',justifyContent:'center',position:'relative',minWidth:sp?'0.3em':'0.95em',height:'1.3em',perspective:'300px',transformStyle:'preserve-3d',background:sp?'transparent':'linear-gradient(180deg,rgba(133,154,222,0.07) 0%,rgba(133,154,222,0.04) 49.5%,rgba(133,154,222,0.06) 50.5%,rgba(133,154,222,0.09) 100%)',borderRadius:4,overflow:'hidden',boxShadow:sp?'none':'0 1px 4px rgba(133,154,222,0.08),inset 0 0.5px 0 rgba(255,255,255,0.6),inset 0 -0.5px 0 rgba(133,154,222,0.06)',border:sp?'none':'0.5px solid rgba(133,154,222,0.1)'}}>{!sp&&<span style={{position:'absolute',left:'6%',right:'6%',top:'50%',height:'0.5px',background:'rgba(133,154,222,0.15)',zIndex:5,pointerEvents:'none'}}/>}<span style={{position:'absolute',inset:0,display:'flex',alignItems:'center',justifyContent:'center',clipPath:'inset(50% 0 0 0)',fontFamily:'inherit',fontSize:'inherit',fontWeight:FTW,lineHeight:1,color:dn?T.accent:'rgba(133,154,222,0.4)',zIndex:1}}>{c.cr}</span><span style={{position:'absolute',inset:0,display:'flex',alignItems:'center',justifyContent:'center',clipPath:'inset(0 0 50% 0)',fontFamily:'inherit',fontSize:'inherit',fontWeight:FTW,lineHeight:1,color:dn?T.accent:'rgba(133,154,222,0.4)',zIndex:2}}>{c.cr}</span>{fl&&c.pv&&<span style={{position:'absolute',inset:0,display:'flex',alignItems:'center',justifyContent:'center',clipPath:'inset(0 0 50% 0)',fontFamily:'inherit',fontSize:'inherit',fontWeight:FTW,lineHeight:1,color:'rgba(133,154,222,0.35)',background:'linear-gradient(180deg,rgba(133,154,222,0.07) 0%,rgba(133,154,222,0.04) 49.5%,rgba(133,154,222,0.06) 50.5%,rgba(133,154,222,0.09) 100%)',transformOrigin:'bottom center',animation:'sfFlip '+FD_+'ms cubic-bezier(0.2,0,0.4,1) forwards',backfaceVisibility:'hidden',zIndex:4,borderRadius:4,boxShadow:'0 2px 6px rgba(133,154,222,0.1)'}}>{c.pv}</span>}{fl&&<span style={{position:'absolute',inset:'50% 0 0 0',background:'linear-gradient(to bottom,rgba(133,154,222,0.06),transparent 80%)',animation:'sfShadow '+FD_+'ms ease-out forwards',zIndex:3,pointerEvents:'none'}}/>}</span>})}{wi<words.length-1&&<span style={{width:'0.6em'}}/>}</span>})}</span>}

function CountUp({value,delay=0,dur=1200}){const num=parseFloat(value);const suffix=value.replace(/[\d.]+/,'');const isNum=!isNaN(num);const[display,setDisplay]=useState(isNum?'0'+suffix:value);useEffect(()=>{if(!isNum)return;let start=null;const tm=setTimeout(()=>{const step=ts=>{if(!start)start=ts;const p=Math.min((ts-start)/dur,1);const ease=1-Math.pow(1-p,3);setDisplay(Math.round(num*ease)+suffix);if(p<1)requestAnimationFrame(step)};requestAnimationFrame(step)},delay);return()=>clearTimeout(tm)},[value,delay]);return display}

function TiltCard({children,style={}}){const ref=useRef(null);const[rot,setRot]=useState({x:0,y:0});return <div ref={ref} onMouseMove={e=>{if(!ref.current)return;const r=ref.current.getBoundingClientRect();const px=(e.clientX-r.left)/r.width;const py=(e.clientY-r.top)/r.height;setRot({x:(0.5-py)*6,y:(px-0.5)*6})}} onMouseLeave={()=>setRot({x:0,y:0})} style={{...style,transform:`perspective(600px) rotateX(${rot.x}deg) rotateY(${rot.y}deg)`,transition:'transform 200ms ease-out',transformStyle:'preserve-3d'}}>{children}</div>}

