cover:({data:d})=><div style={{display:"flex",flexDirection:"column",justifyContent:"center",alignItems:"center",height:"100%",textAlign:"center",padding:"0 60px"}}><A delay={80} anim="fadeIn" dur={700}><div style={{fontSize:11,fontFamily:FM,fontWeight:500,color:T.accent,letterSpacing:"0.14em",textTransform:"uppercase",marginBottom:26}}>{d.eyebrow}</div></A><A delay={200} anim="scaleBlur" dur={700}><div style={{position:"relative",overflow:"hidden",borderRadius:8,padding:"4px 8px"}}><h1 style={{fontSize:30,fontFamily:FT,fontWeight:FTW,color:T.heading,textAlign:"center",maxWidth:900,margin:"0 auto",lineHeight:1.25,maxWidth:960,marginBottom:26,letterSpacing:"-0.02em",position:"relative",zIndex:1}}><SF t={d.title}/></h1><div style={{position:"absolute",inset:0,background:"linear-gradient(100deg,transparent 20%,rgba(133,154,222,0.15) 50%,transparent 80%)",animation:"lightSweep 1.4s cubic-bezier(0.22,1,0.36,1) 1.2s both",pointerEvents:"none"}}/></div></A><A delay={400} anim="fadeUp" dur={500}>{d.subtitle&&<div style={{fontSize:14,fontFamily:FB,color:T.body,marginBottom:44}}>{d.subtitle}</div>}</A><A delay={540} anim="popIn" dur={400}><div style={{display:"flex",flexDirection:"column",alignItems:"center",gap:5}}><div style={{width:48,height:48,borderRadius:"50%",background:"#FFFFFF",display:"flex",alignItems:"center",justifyContent:"center",boxShadow:"0 4px 16px rgba(133,154,222,0.3)",animation:"glowPulse 5s ease-in-out infinite",overflow:"hidden"}}><img src="/fonts/icon.png" alt="" style={{width:"110%",height:"110%",objectFit:"cover",borderRadius:"50%",marginLeft:"-20%"}}/></div><div style={{fontSize:15,fontFamily:FD,fontWeight:500,color:T.heading,marginTop:7}}>{d.author}</div><div style={{fontSize:11,fontFamily:FB,color:T.bodyLight}}>{d.role}</div></div></A></div>,

agenda:({data:d})=>{const ic=[I.compass,I.telescope,I.grid,I.bookmark,I.flag];return <div style={{padding:"40px 40px",height:"100%",display:"flex",flexDirection:"column",justifyContent:"center",maxWidth:1500,margin:"0 auto"}}><A delay={40} anim="driftR" dur={500}><h2 style={{fontSize:28,fontFamily:FT,fontWeight:FTW,color:T.heading,textAlign:"center",width:"100%",textTransform:"lowercase",marginBottom:40}}><SF t={d.title}/></h2></A><div style={{position:"relative"}}><A delay={80} anim="fadeIn" dur={600}><div style={{position:"absolute",top:18,left:"5%",right:"5%",height:2,background:`linear-gradient(90deg,${T.divider},${T.accent},${T.divider})`,backgroundSize:"300% 100%",animation:"hlPulse 14s linear infinite",borderRadius:1,zIndex:0}}/></A><div style={{display:"grid",gridTemplateColumns:`repeat(${d.items.length},1fr)`,gap:8,position:"relative",zIndex:1}}>{d.items.map((it,i)=><A key={i} delay={120+i*80} anim="glideUp" dur={450}><div style={{display:"flex",flexDirection:"column",alignItems:"center"}}><div style={{width:36,height:36,borderRadius:"50%",background:`linear-gradient(135deg,${T.accent},${T.headingDark})`,display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0,boxShadow:"0 3px 10px rgba(133,154,222,0.3),inset 0 1px 2px rgba(255,255,255,0.2)",marginBottom:14}}><div style={{color:T.white,transform:"scale(0.7)",display:"flex",alignItems:"center",justifyContent:"center",width:"100%",height:"100%"}}>{ic[i](T.white)}</div></div><div style={{background:T.cardBg,border:`1px solid ${T.cardBorder}`,borderRadius:12,padding:"14px 14px",boxShadow:T.cardShadow,width:"100%",textAlign:"center"}}><div style={{fontSize:13,fontFamily:FD,fontWeight:500,color:T.heading,marginBottom:4}}>{it.l}</div><div style={{fontSize:11,fontFamily:FB,color:T.body,lineHeight:1.55}}>{it.d}</div></div></div></A>)}</div></div></div>},

