direction:({data:d,slideIdx:si})=>{const _dra=[["clipL","slideL","floatIn"],["clipR","driftR","tumbleIn"]];const _dri={19:0,20:1};const _anims=(bookV4||bookV5||bookV6)?_dra[_dri[si]!=null?_dri[si]:si%2]:["clipL","slideL","floatIn"];return <div style={{padding:"36px 30px",height:"100%",display:"flex",flexDirection:"column",justifyContent:"center",maxWidth:1200,margin:"0 auto"}}><A delay={40} anim={_anims[0]}><h2 style={{fontSize:24,fontFamily:FT,fontWeight:FTW,color:T.heading,textAlign:"center",width:"100%",textTransform:"lowercase",marginBottom:20}}><SF t={d.title}/></h2></A><A delay={120} anim={_anims[1]} style={{marginBottom:28}}><div style={{background:T.cardBg,border:`1px solid ${T.cardBorder}`,borderRadius:14,padding:"24px 22px",boxShadow:T.cardShadow,maxWidth:470,margin:"0 auto"}}><div style={{fontSize:16,fontFamily:FD,fontWeight:500,color:T.heading,marginBottom:14}}>{d.card.l}</div>{d.card.bullets.map((b,i)=><div key={i} style={{display:"flex",gap:8,marginBottom:8,alignItems:"flex-start"}}><span style={{fontSize:7,color:T.accent,marginTop:5}}>●</span><span style={{fontSize:12.5,fontFamily:FB,color:T.body,lineHeight:1.6}}>{b}</span></div>)}<div style={{display:"flex",gap:16,marginTop:14}}><div style={{flex:1,padding:"10px 14px",background:"rgba(133,154,222,0.06)",borderRadius:8}}><div style={{fontSize:9,fontFamily:FM,color:T.accent,textTransform:"uppercase",letterSpacing:"0.08em",marginBottom:3}}>Pros</div><div style={{fontSize:11,fontFamily:FB,color:T.body,lineHeight:1.5}}>{d.card.pros}</div></div><div style={{flex:1,padding:"10px 14px",background:T.surface,borderRadius:8}}><div style={{fontSize:9,fontFamily:FM,color:T.bodyLight,textTransform:"uppercase",letterSpacing:"0.08em",marginBottom:3}}>Limits</div><div style={{fontSize:11,fontFamily:FB,color:T.body,lineHeight:1.5}}>{d.card.limits}</div></div></div></div></A><A delay={250} anim={_anims[2]} dur={600}><img src={d.img} alt="" style={{width:"100%",borderRadius:12,border:"none",boxShadow:"0 8px 28px rgba(133,154,222,0.14),0 2px 8px rgba(0,0,0,0.06)"}}/></A></div>},
journey:({data:d})=>{const fr=d.friction||[];return <div style={{padding:"36px 140px",height:"100%",display:"flex",flexDirection:"column",justifyContent:"center",alignItems:"center",width:"100%"}}><A delay={40} anim="slideR"><h2 style={{fontSize:24,fontFamily:FT,fontWeight:FTW,color:T.heading,textAlign:"center",width:"100%",textTransform:"lowercase",marginBottom:44}}><SF t={d.title}/></h2></A><div style={{position:"relative",width:"100%"}}><svg style={{position:"absolute",top:"50%",left:0,width:"100%",height:120,transform:"translateY(-50%)",zIndex:0,animation:"drawLineIn 1.4s cubic-bezier(0.22,1,0.36,1) 200ms both"}} preserveAspectRatio="none" viewBox="0 0 1000 120"><path d="M0 60 C60 -10,190 130,250 60 C310 -10,440 130,500 60 C560 -10,690 130,750 60 C810 -10,940 130,1000 60" fill="none" stroke={T.accent} strokeWidth="3" strokeDasharray="1,8" strokeLinecap="round" opacity="0.3"/></svg><div style={{display:"flex",justifyContent:"space-between",position:"relative",zIndex:1,gap:8}}>{d.steps.map((s,i)=>{const isFr=fr.includes(i);const isTop=i%2===0;return <A key={i} delay={120+i*80} anim="tumbleIn" dur={400}><div style={{display:"flex",flexDirection:"column",alignItems:isTop?"center":"center",width:190,animation:`bobFloat ${4+i*0.8}s ease-in-out ${i*0.5}s infinite`}}>{isTop&&<div style={{background:"#FFFFFF",border:`1px solid ${T.cardBorder}`,borderRadius:12,padding:"14px 14px",boxShadow:T.cardShadow,animation:"none",marginBottom:8,width:"100%"}}><div style={{fontSize:13,fontFamily:FD,fontWeight:500,color:T.heading,textAlign:"center",marginBottom:4}}>{s.l}</div><div style={{fontSize:10.5,fontFamily:FB,color:T.body,lineHeight:1.5,textAlign:"center"}}>{s.d}</div></div>}<div style={{width:28,height:28,borderRadius:"50%",background:`linear-gradient(135deg,${T.accent},${T.headingDark})`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:10,fontFamily:FD,fontWeight:500,color:T.white,lineHeight:1,flexShrink:0,boxShadow:"0 2px 8px rgba(133,154,222,0.3)",animation:`nodeGlow ${3+i*0.3}s ease-in-out ${i*0.2}s infinite`}}>{i+1}</div>{!isTop&&<div style={{background:"#FFFFFF",border:`1px solid ${T.cardBorder}`,borderRadius:12,padding:"14px 14px",boxShadow:T.cardShadow,animation:"none",marginTop:8,width:"100%"}}><div style={{fontSize:13,fontFamily:FD,fontWeight:500,color:T.heading,textAlign:"center",marginBottom:4}}>{s.l}</div><div style={{fontSize:10.5,fontFamily:FB,color:T.body,lineHeight:1.5,textAlign:"center"}}>{s.d}</div></div>}</div></A>})}</div></div></div>},

