function FontThemeDropdown({ label, options, value, onChange, icon }) {
  const [open, setOpen] = useState(false);
  const ref = useRef(null);
  useEffect(() => {
    const handler = (e) => { if (ref.current && !ref.current.contains(e.target)) setOpen(false); };
    document.addEventListener("mousedown", handler);
    return () => document.removeEventListener("mousedown", handler);
  }, []);
  return (
    <div ref={ref} style={{ position: "relative" }}>
      <button onClick={() => setOpen(!open)} style={{
        display: "flex", alignItems: "center", gap: 5, padding: "5px 10px", borderRadius: 7,
        border: "1px solid " + T.cardBorder, background: open ? T.accentDim : T.white,
        color: T.heading, fontSize: 10, fontFamily: FM, cursor: "pointer",
        transition: "all 150ms ease-out", boxShadow: T.cardShadow,
      }}
        onMouseEnter={e => { if (!open) e.currentTarget.style.background = T.surface; }}
        onMouseLeave={e => { if (!open) e.currentTarget.style.background = open ? T.accentDim : T.white; }}
      >{icon}{label}</button>
      {open && (
        <div style={{
          position: "absolute", top: "calc(100% + 6px)", right: 0, minWidth: 220,
          background: T.white, border: "1px solid " + T.cardBorder, borderRadius: 12,
          boxShadow: "0 12px 40px rgba(100,120,180,0.12)", padding: "8px 6px", zIndex: 200,
          animation: "fadeUp 180ms " + EO + " both",
        }}>
          {Object.keys(options).map(k => (
            <div key={k} onClick={() => { onChange(k); setOpen(false); }}
              style={{
                padding: "7px 12px", borderRadius: 7, fontSize: 11, fontFamily: FB,
                color: k === value ? T.heading : T.body, fontWeight: k === value ? 600 : 400,
                background: k === value ? T.accentDim : "transparent",
                cursor: "pointer", transition: "all 120ms ease",
              }}
              onMouseEnter={e => { if (k !== value) e.currentTarget.style.background = T.surface; }}
              onMouseLeave={e => { if (k !== value) e.currentTarget.style.background = "transparent"; }}
            >{k}</div>
          ))}
        </div>
      )}
    </div>
  );
}

function FontPanel({ fonts, setFonts }) {
  const [open, setOpen] = useState(false);
  const ref = useRef(null);
  useEffect(() => {
    const handler = (e) => { if (ref.current && !ref.current.contains(e.target)) setOpen(false); };
    document.addEventListener("mousedown", handler);
    return () => document.removeEventListener("mousedown", handler);
  }, []);
  return (
    <div ref={ref} style={{ position: "relative" }}>
      <button onClick={() => setOpen(!open)} style={{
        display: "flex", alignItems: "center", gap: 5, padding: "5px 10px", borderRadius: 7,
        border: "1px solid " + T.cardBorder, background: open ? T.accentDim : T.white,
        color: T.heading, fontSize: 10, fontFamily: FM, cursor: "pointer",
        transition: "all 150ms ease-out", boxShadow: T.cardShadow,
      }}
        onMouseEnter={e => { if (!open) e.currentTarget.style.background = T.surface; }}
        onMouseLeave={e => { if (!open) e.currentTarget.style.background = open ? T.accentDim : T.white; }}
      ><svg width="12" height="12" viewBox="0 0 16 16" fill="none"><path d="M3 12.5L8 3l5 9.5H3z" stroke="currentColor" strokeWidth="1.3" strokeLinejoin="round"/><line x1="5.5" y1="9.5" x2="10.5" y2="9.5" stroke="currentColor" strokeWidth="1.2"/></svg>Fonts</button>
      {open && (
        <div style={{
          position: "absolute", top: "calc(100% + 6px)", right: 0, width: 260,
          maxHeight: "calc(100vh - 140px)", overflowY: "auto",
          background: T.white, border: "1px solid " + T.cardBorder, borderRadius: 14,
          boxShadow: "0 12px 40px rgba(100,120,180,0.12)", padding: "14px 12px", zIndex: 200,
          animation: "fadeUp 180ms " + EO + " both",
        }}>
          <div style={{ fontSize: 9.5, fontFamily: FM, color: T.accent, textTransform: "uppercase", letterSpacing: "0.1em", marginBottom: 10 }}>Font Selection</div>
          {[
            { label: "Slide titles", key: "title", opts: FONT_TITLES },
            { label: "Headings", key: "heading", opts: FONT_HEADINGS },
            { label: "Body & captions", key: "body", opts: FONT_BODY },
          ].map(cat => (
            <div key={cat.key} style={{ marginBottom: 10 }}>
              <div style={{ fontSize: 10, fontFamily: FM, color: T.bodyLight, marginBottom: 4 }}>{cat.label}</div>
              <div style={{ display: "flex", flexWrap: "wrap", gap: 4 }}>
                {Object.keys(cat.opts).map(name => (
                  <button key={name} onClick={() => setFonts(f => ({ ...f, [cat.key]: name }))}
                    style={{
                      padding: "4px 8px", borderRadius: 6, fontSize: 10.5,
                      fontFamily: cat.opts[name], fontWeight: fonts[cat.key] === name ? 600 : 400,
                      border: "1px solid " + (fonts[cat.key] === name ? T.accent : T.cardBorder),
                      background: fonts[cat.key] === name ? T.accentDim : "transparent",
                      color: fonts[cat.key] === name ? T.heading : T.body,
                      cursor: "pointer", transition: "all 120ms ease",
                    }}
                  >{name}</button>
                ))}
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

